    _mm256_store_pd(&spill_re[55*4],x7_re);
    _mm256_store_pd(&spill_im[55*4],x7_im);

    /* sub-FFT n2=7 */
    x0_re = LD(&in_re[7*vs]);
    x0_im = LD(&in_im[7*vs]);
    x1_re = LD(&in_re[15*vs]);
    x1_im = LD(&in_im[15*vs]);
