    ST(&out_im[48*vs],x6_im);
    ST(&out_re[56*vs],x7_re);
    ST(&out_im[56*vs],x7_im);

    /* column k1=1 */
    x0_re = _mm256_load_pd(&spill_re[1*4]);
    x0_im = _mm256_load_pd(&spill_im[1*4]);
    x1_re = _mm256_load_pd(&spill_re[9*4]);
