        x5_re = LD(&in_re[41*K+k]);
        x5_im = LD(&in_im[41*K+k]);
        { __m256d wr = _mm256_load_pd(&tw_re[40*K+k]);
          __m256d wi = _mm256_load_pd(&tw_im[40*K+k]);
          __m256d tr = x5_re;
          x5_re = _mm256_fmsub_pd(x5_re,wr,_mm256_mul_pd(x5_im,wi));
          x5_im = _mm256_fmadd_pd(tr,wi,_mm256_mul_pd(x5_im,wr)); }
        x6_re = LD(&in_re[49*K+k]);
