        x0_re = LD(&in_re[7*K+k]);
        x0_im = LD(&in_im[7*K+k]);
        x1_re = LD(&in_re[15*K+k]);
        x1_im = LD(&in_im[15*K+k]);
        x2_re = LD(&in_re[23*K+k]);
        x2_im = LD(&in_im[23*K+k]);
