        x6_re = LD(&in_re[55*K+k]);
        x6_im = LD(&in_im[55*K+k]);
        x7_re = LD(&in_re[63*K+k]);
        x7_im = LD(&in_im[63*K+k]);

        /* radix-8 n2=7 [bwd] (split) */
