              const __m256d B1r=_mm256_mul_pd(sqrt2_inv,_mm256_sub_pd(_B1r,_B1i)), B1i=_mm256_mul_pd(sqrt2_inv,_mm256_add_pd(_B1r,_B1i));
              const __m256d _B3r=_mm256_add_pd(oqr,osi), _B3i=_mm256_sub_pd(oqi,osr);
