          const __m256d _B3r=_mm256_add_pd(oqr,osi), _B3i=_mm256_sub_pd(oqi,osr);
          const __m256d B3r=_mm256_mul_pd(nsqrt2_inv,_mm256_add_pd(_B3r,_B3i)), B3i=_mm256_mul_pd(sqrt2_inv,_mm256_sub_pd(_B3r,_B3i));
