              __m256d orr=_mm256_add_pd(x3_re,x7_re), ori=_mm256_add_pd(x3_im,x7_im);
              __m256d osr=_mm256_sub_pd(x3_re,x7_re), osi=_mm256_sub_pd(x3_im,x7_im);
              const __m256d B0r=_mm256_add_pd(opr,orr), B0i=_mm256_add_pd(opi,ori);
