        _mm256_store_pd(&spill_im[63*4],x7_im);

        /* PASS 2 */

        /* column k1=0 */
        x0_re = _mm256_load_pd(&spill_re[0*4]);
        x0_im = _mm256_load_pd(&spill_im[0*4]);
