        x2_re = _mm256_load_pd(&spill_re[17*4]);
        x2_im = _mm256_load_pd(&spill_im[17*4]);
        x3_re = _mm256_load_pd(&spill_re[25*4]);
        x3_im = _mm256_load_pd(&spill_im[25*4]);
